  "onboarding.welcome": "Welcome to Liminal.",
  "onboarding.welcomeSubtitle": "Let’s take a moment to set up your portrait.\nThis is the context that shapes every Mirror response —\nthe more context you provide, the more relevant the responses can be.\n\nIt takes about two minutes. You can always update it later.",
  "onboarding.skip": "Skip for now",
  "onboarding.skipCompletely": "Don’t show again",
  "onboarding.whoYouAre": "Who you are",
  "onboarding.whoYouAreSubtitle": "First, tell us a little about yourself.",
  "onboarding.preferredName": "Preferred name",
  "onboarding.preferredNamePlaceholder": "What would you like to be called?",
  "onboarding.pronouns": "Pronouns",
  "onboarding.pronounsPlaceholder": "e.g. he/him, she/her, they/them",
  "onboarding.sex": "Sex",
  "onboarding.birthDetails": "Your birth details",
  "onboarding.birthDetailsSubtitle": "Date of birth is required so we can confirm you’re old enough to use Liminal.\nTime and place are optional — they refine the astrological profile.",
  "onboarding.dateOfBirth": "Date of birth",
  "onboarding.dobRequiredHint": "Required — used to confirm you are old enough to use Liminal.",
  "onboarding.dobUnderAge": "Liminal isn’t designed for people under 16. We can’t continue with onboarding.",
  "onboarding.dobInvalid": "Please enter a valid date of birth.",
  "onboarding.timeOfBirth": "Time of birth",
  "onboarding.timeHint": "Optional — needed for Moon and Rising signs",
  "onboarding.placeOfBirth": "Place of birth",
  "onboarding.placeHint": "Optional — needed for Rising sign",
  "onboarding.placePlaceholder": "e.g. Melbourne, Australia",
